<div class="card"><h3>SLA Policies</h3><table><thead><tr><th>Policy</th><th>Scope</th><th>Response</th><th>Resolution</th><th>Status</th><th>Actions</th></tr></thead><tbody><?php foreach ($policies as $policy): ?><tr><td><?= e($policy['policy_name']) ?></td><td><?= e($policy['target_scope']) ?></td><td><?= e((string)$policy['response_minutes']) ?> min</td><td><?= e((string)$policy['resolution_minutes']) ?> min</td><td><?= !empty($policy['is_active']) ? 'Active' : 'Inactive' ?></td><td><?php if (\App\Core\Auth::can('sla','edit')): ?><form method="post" style="display:inline-block"><?= csrf_field() ?><input type="hidden" name="action" value="update"><input type="hidden" name="id" value="<?= e((string)$policy['id']) ?>"><input type="text" name="policy_name" value="<?= e($policy['policy_name']) ?>" style="width:120px"><input type="text" name="target_scope" value="<?= e($policy['target_scope']) ?>" style="width:90px"><input type="number" min="1" name="response_minutes" value="<?= e((string)$policy['response_minutes']) ?>" style="width:80px"><input type="number" min="1" name="resolution_minutes" value="<?= e((string)$policy['resolution_minutes']) ?>" style="width:80px"><label><input type="checkbox" name="is_active" value="1" <?= !empty($policy['is_active']) ? 'checked' : '' ?>> Active</label><button type="submit">Save</button></form><?php endif; ?> <?php if (\App\Core\Auth::can('sla','delete')): ?><form method="post" style="display:inline-block" onsubmit="return confirm('Delete this policy?')"><?= csrf_field() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?= e((string)$policy['id']) ?>"><button type="submit">Delete</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div>
<div class="card"><h3>Escalation Rules</h3><table><thead><tr><th>Rule</th><th>Match</th><th>Delay</th><th>Action</th><th>Status</th><th>Actions</th></tr></thead><tbody><?php foreach ($rules as $rule): ?><tr><td><?= e($rule['rule_name']) ?></td><td><?= e($rule['priority_name'] ?: 'Any priority') ?><?php if (!empty($rule['category_name'])): ?><div class="meta">Category: <?= e($rule['category_name']) ?></div><?php endif; ?></td><td><?= e((string)$rule['hours_after_breach']) ?> hr after breach</td><td><div class="meta">Owner: <?= e((string)($rule['escalate_to_user_id'] ?: 'keep current')) ?></div><div class="meta">Priority: <?= e((string)($rule['set_priority_name'] ?: 'keep current')) ?></div><div class="meta">Status: <?= e((string)$rule['set_status_name']) ?></div></td><td><?= !empty($rule['is_active']) ? 'Active' : 'Inactive' ?></td><td><?php if (\App\Core\Auth::can('sla','edit')): ?><form method="post" class="stack-form"><?= csrf_field() ?><input type="hidden" name="action" value="rule_update"><input type="hidden" name="id" value="<?= e((string)$rule['id']) ?>"><div class="grid grid-2"><input type="text" name="rule_name" value="<?= e($rule['rule_name']) ?>"><input type="text" name="category_name" value="<?= e((string)$rule['category_name']) ?>" placeholder="Category"></div><div class="grid grid-4"><select name="priority_name"><option value="">Any priority</option><?php foreach (['Low','Normal','High','Urgent'] as $priority): ?><option value="<?= e($priority) ?>" <?= $rule['priority_name'] === $priority ? 'selected' : '' ?>><?= e($priority) ?></option><?php endforeach; ?></select><input type="number" min="0" name="hours_after_breach" value="<?= e((string)$rule['hours_after_breach']) ?>"><select name="escalate_to_user_id"><option value="">Keep current owner</option><?php foreach ($users as $user): ?><option value="<?= e((string)$user['id']) ?>" <?= (int)$rule['escalate_to_user_id'] === (int)$user['id'] ? 'selected' : '' ?>><?= e($user['full_name']) ?></option><?php endforeach; ?></select><select name="set_priority_name"><option value="">Keep current priority</option><?php foreach (['High','Urgent'] as $priority): ?><option value="<?= e($priority) ?>" <?= $rule['set_priority_name'] === $priority ? 'selected' : '' ?>><?= e($priority) ?></option><?php endforeach; ?></select></div><div class="grid grid-3"><select name="set_status_name"><?php foreach (['Escalated','Investigating','Waiting'] as $status): ?><option value="<?= e($status) ?>" <?= $rule['set_status_name'] === $status ? 'selected' : '' ?>><?= e($status) ?></option><?php endforeach; ?></select><input type="number" min="0" name="sort_order" value="<?= e((string)$rule['sort_order']) ?>"><label><input type="checkbox" name="is_active" value="1" <?= !empty($rule['is_active']) ? 'checked' : '' ?>> Active</label></div><textarea name="comment_template" rows="3"><?= e($rule['comment_template']) ?></textarea><button type="submit">Save Rule</button></form><?php endif; ?> <?php if (\App\Core\Auth::can('sla','delete')): ?><form method="post" onsubmit="return confirm('Delete this rule?')"><?= csrf_field() ?><input type="hidden" name="action" value="rule_delete"><input type="hidden" name="id" value="<?= e((string)$rule['id']) ?>"><button type="submit">Delete</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div>
